import{_ as o,o as t,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-046 — Agency-first build-time imagery sourcing","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-046.md","filePath":"adr/ADR-046.md"}'),s={name:"adr/ADR-046.md"};function i(n,e,d,c,l,m){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-046-—-agency-first-build-time-imagery-sourcing" tabindex="-1">ADR-046 — Agency-first build-time imagery sourcing <a class="header-anchor" href="#adr-046-—-agency-first-build-time-imagery-sourcing" aria-label="Permalink to &quot;ADR-046 — Agency-first build-time imagery sourcing&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-06 Extends · <code>docs/adr/ADR-016.md</code> (build-time bundle unchanged) Scope · <code>scripts/fetch-assets.ts</code>, mission/panel/ISS imagery under <code>static/images/</code></p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-016 requires all imagery to be fetched at <strong>build time</strong> and served from the app host. Today <code>scripts/fetch-assets.ts</code> leans heavily on the <strong>NASA Images API</strong> plus curated Wikimedia Commons filenames. That often yields correct NASA missions but <strong>wrong context</strong> for non-NASA operators (e.g. Soyuz, Tiangong, SpaceX hardware) or generic diagrams when agency-specific sources were never queried first.</p><p>Product expectation: <strong>prefer imagery from the agency that operated the mission or object</strong>, then fall back to partner archives and general libraries.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><ol><li><p><strong>Build-time only</strong> — No change to ADR-016: production still ships zero runtime third-party image URLs.</p></li><li><p><strong>Primary source = operating agency</strong> (conceptual rule; encoded per entity in fetch helpers):</p><ul><li><strong>Roscosmos / Soviet heritage</strong> — Russian programmes (e.g. Soyuz, GLONASS-class editorial, lunar/rovers where Roscosmos holds primary press assets).</li><li><strong>CNSA</strong> — Chinese programmes (e.g. Tiangong, Chang’e, Tianwen where Chinese agencies publish primary material).</li><li><strong>SpaceX</strong> — SpaceX vehicles and programmes where SpaceX (or explicitly licensed partner releases) are the authoritative visual source.</li><li><strong>NASA</strong> — NASA-led missions and <strong>default baseline</strong> when ownership is US NASA primary or no tighter agency mapping exists.</li></ul></li><li><p><strong>Fallback order</strong> (when primary yields nothing usable — HTTP failure, empty catalog, policy block):</p><ul><li>Co-operating / partner agency archives (e.g. ESA for joint programmes where applicable).</li><li><strong>Wikimedia Commons</strong> — curated filenames verified PD / CC-* compatible with our credits pipeline.</li><li><strong>NASA Images API</strong> — retained as a <strong>broad aerospace library</strong>, not the automatic first hop for every entity.</li></ul></li><li><p><strong>Mixed programmes</strong> (e.g. ISS): use an explicit <strong>published rule table</strong> in implementation — e.g. primary poster / lead partner for that catalog row — so behaviour is deterministic in CI.</p></li><li><p><strong>License &amp; attribution</strong> — Each adapter records provenance so gallery credits remain accurate (NASA PD-style vs ESA CC BY-SA IGO vs Commons attribution). Implementation must not merge incompatible license strings blindly into one generic “NASA” credit.</p></li></ol><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li>Aligns hero/gallery imagery with <strong>who flew the hardware</strong>, improving trust and editorial clarity.</li><li>Keeps offline-first and ADR-016 contracts intact.</li><li>Makes NASA a <strong>strong fallback</strong>, not a silent substitute for agency-owned stories.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>NASA-only forever</strong> — simplest implementation; rejected for context mismatches above.</li><li><strong>Wikimedia-only</strong> — good for PD/CC breadth; weak as sole primary for agency-branded campaigns.</li><li><strong>Runtime agency APIs</strong> — violates ADR-016; rejected.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive:</p><ul><li>Clearer editorial policy for future fetch helpers and curated lists.</li></ul><p>Negative:</p><ul><li>More adapters and maintenance (rate limits, URL churn per agency).</li><li>Legal/editorial review for non-NASA terms until helpers are stable.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><strong><code>scripts/agency-mission-sources.ts</code></strong> — <code>normalizeAgency()</code> maps <code>index.json</code> agency strings to a closed key; <code>fetchAgencyPrimaryImageUrls()</code> returns NASA Images API preview URLs <strong>only</strong> for <code>NASA</code> (build-time “agency HTTP primary”). Other keys return <code>[]</code>; editorial primary for those operators is the <strong>curated Wikimedia</strong> lists in <code>scripts/fetch-assets.ts</code>.</li><li><strong><code>scripts/fetch-assets.ts</code></strong> — <code>fetchMissionImages</code> pipeline (per mission): optional Commons hero (<code>commonsCoverFirst</code>) → agency primary (NASA API only when <code>normalizeAgency(agency) === &#39;NASA&#39;</code>) → Wikimedia single + gallery top-up → <strong>NASA fallback</strong> for non-NASA agencies to fill remaining slots up to <code>MISSION_GALLERY_MAX</code>. Legacy fetch ids <strong><code>mars2</code> / <code>mars6</code></strong> (not in <code>index.json</code>) resolve agency via <code>static/data/missions/{mars,moon}/{id}.json</code> when present, else <strong><code>ROSCOSMOS</code></strong>.</li><li><strong><code>fetchNasaGalleryUrls(query, max, missionId?)</code></strong> — credit filter accepts NASA-family <code>secondary_creator</code> substrings by default; <strong><code>missionId</code>-scoped</strong> extras in <code>MISSION_NASA_CREDIT_EXTRAS</code> allow partner imagery (e.g. <code>esa</code> for <code>mars-express</code>, <code>jaxa</code> for <code>mmx</code> / <code>slim</code>, <code>mbrsc</code> / <code>emirates</code> for <code>hope-probe</code>) when NASA hosts the asset.</li><li>Evidence and spike <strong>go/no-go</strong> per operator: <strong><code>docs/research/agency-mission-image-sources.md</code></strong>.</li><li><strong><code>docs/adr/index.md</code></strong> lists this ADR; mission imagery bullet in ADR-016 references this decision for <strong>source priority</strong> (not transport).</li></ul><h3 id="agency-matrix-mission-gallery" tabindex="-1">Agency matrix (mission gallery) <a class="header-anchor" href="#agency-matrix-mission-gallery" aria-label="Permalink to &quot;Agency matrix (mission gallery)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agency (index)</th><th>Mission ids (36)</th><th>Build-time “primary” in code</th><th>NASA fallback</th></tr></thead><tbody><tr><td>NASA</td><td>mariner4, viking1, mars-pathfinder, curiosity, maven, insight, perseverance, apollo11, apollo17, clementine, lro, artemis2, artemis3, galileo, voyager-2, new-horizons, dawn</td><td>NASA Images API after Commons hero</td><td>Wikimedia top-up after API pass</td></tr><tr><td>ROSCOSMOS</td><td>mars3, luna9, luna17, luna24</td><td>Curated Commons (+ <code>mars2</code> / <code>mars6</code> fetch-only)</td><td>Yes (historic / PIA-style queries)</td></tr><tr><td>ESA</td><td>mars-express</td><td>Curated Commons</td><td>Yes (<code>MISSION_NASA_CREDIT_EXTRAS</code>)</td></tr><tr><td>CNSA</td><td>tianwen1, change4, change5, change6</td><td>Curated Commons</td><td>Yes (thin; query-tuned)</td></tr><tr><td>ISRO</td><td>mangalyaan, chandrayaan1, chandrayaan3</td><td>Curated Commons</td><td>Yes</td></tr><tr><td>JAXA</td><td>mmx, slim</td><td>Curated Commons</td><td>Yes (<code>jaxa</code> allowlist for <code>mmx</code> / <code>slim</code>)</td></tr><tr><td>UAESA</td><td>hope-probe</td><td>Curated Commons</td><td>Yes (<code>hope-probe</code> allowlist)</td></tr><tr><td>SpaceX</td><td>starship-demo, starship-mars-crew</td><td>Curated Commons</td><td>Yes (cooperation imagery only; credit filter)</td></tr><tr><td>Blue Origin</td><td>blue-moon-mk1</td><td>Curated Commons</td><td>Yes</td></tr><tr><td>Inspiration Mars</td><td>inspiration-mars</td><td>Curated Commons</td><td>Yes</td></tr></tbody></table><h3 id="github-44-checklist-per-agency-—-copy-into-issue-as-needed" tabindex="-1">GitHub #44 checklist (per agency — copy into issue as needed) <a class="header-anchor" href="#github-44-checklist-per-agency-—-copy-into-issue-as-needed" aria-label="Permalink to &quot;GitHub #44 checklist (per agency — copy into issue as needed)&quot;">​</a></h3><ul><li>[ ] <strong>NASA</strong> — <code>primary:nasa-api</code> path + Wikimedia top-up; spot-check <code>MISSION_GALLERY_MAX</code> for outer-planet catalogue ids.</li><li>[ ] <strong>ROSCOSMOS</strong> — Commons lists for <code>mars3</code>, <code>luna*</code>, <code>mars2</code>, <code>mars6</code>; NASA fallback honest credits.</li><li>[ ] <strong>ESA</strong> — <code>mars-express</code> Commons + <code>MISSION_NASA_CREDIT_EXTRAS[&#39;mars-express&#39;]</code>; no standalone ESA HTTP adapter (spike no-go).</li><li>[ ] <strong>CNSA</strong> — Chang’e / Tianwen Commons gallery depth.</li><li>[ ] <strong>ISRO</strong> — MOM + Chandrayaan Commons gallery depth.</li><li>[ ] <strong>JAXA</strong> — <code>slim</code> / <code>mmx</code> Commons + JAXA credit allowlist for NASA fallback; no JAXA Digital Archives adapter (spike no-go).</li><li>[ ] <strong>UAESA</strong> — Hope Commons + <code>hope-probe</code> allowlist; no MBRSC scrape adapter (spike no-go).</li><li>[ ] <strong>SpaceX</strong> — Starship Commons; NASA fallback only when credits match.</li><li>[ ] <strong>Blue Origin</strong> — Blue Moon Commons + NASA tight query.</li><li>[ ] <strong>Inspiration Mars</strong> — Commons concept art aligned to mission <code>credit</code> JSON.</li></ul><h3 id="earth-object-iss-unchanged-scope-here" tabindex="-1">Earth-object / ISS (unchanged scope here) <a class="header-anchor" href="#earth-object-iss-unchanged-scope-here" aria-label="Permalink to &quot;Earth-object / ISS (unchanged scope here)&quot;">​</a></h3><p>Agency-specific behaviour continues via <strong>explicit</strong> <code>skipNasa</code>, <code>commonsHeroFirst</code>, and query strings per row (tiangong, geo, glonass, beidou, …). Optional follow-on: reuse <code>normalizeAgency</code> for a shared router.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-016 — build-time assets (transport).</li><li>Research — <code>docs/research/agency-mission-image-sources.md</code>.</li><li>Implementation tracking: GitHub <strong>#44</strong> — <em>Implement ADR-046: agency-first build-time imagery sourcing</em> (use checklist above).</li></ul>',26)])])}const h=o(s,[["render",i]]);export{p as __pageData,h as default};
